-- Vytvoření tabulek
CREATE {{TABLE}} students (
    id       INTEGER PRIMARY KEY {{AUTOINCREMENT}},
    name     TEXT    NOT NULL,
    email    TEXT    UNIQUE,
    grade_id INTEGER {{REFERENCES}} grades(id)
);

-- JOIN dotaz
SELECT s.name, g.label AS grade
FROM {{students}} s
{{JOIN}} grades g ON s.grade_id = {{g}}.id
WHERE s.grade_id IS NOT {{NULL}}
ORDER BY s.name {{ASC}};

-- Agregace
SELECT grade_id, {{COUNT}}(*) AS num_students, {{AVG}}(score) AS avg_score
FROM students
GROUP BY {{grade_id}}
HAVING COUNT(*) > {{5}};

import {{sqlite3}}

conn = sqlite3.connect('school.db')
conn.{{row_factory}} = sqlite3.Row

def create_student(name: str, email: str, grade_id: int):
    with {{conn}}:
        conn.execute(
            "INSERT INTO students (name, email, grade_id) VALUES (?,?,?)",
            ({{name}}, email, grade_id)
        )

def get_students_by_grade(grade_id: int):
    cur = conn.{{cursor}}()
    cur.execute(
        "SELECT * FROM students WHERE grade_id = ? ORDER BY name",
        ({{grade_id}},)
    )
    return cur.{{fetchall}}()

def update_grade(student_id: int, new_grade: int):
    with conn:
        conn.execute("UPDATE students SET grade_id = ? WHERE id = ?",
                     (new_grade, {{student_id}}))
